			if gotInf != 1 {
				t.Fatalf("+Inf count = %d, want 1", gotInf)
			}
			if gotSum != tt.value {
				t.Fatalf("sum = %v, want %v", gotSum, tt.value)
			}
			if gotCount != 1 {
				t.Fatalf("count = %d, want 1", gotCount)
			}
		})
	}
}

func TestHistogramObserveCumulativeCountsAndTotals(t *testing.T) {
	h := New().NewHistogram("h", "hh", []float64{1, 10, 100})
	values := []float64{0.5, 1, 1.1, 9.9, 10, 10.1, 99.9, 100, 100.1}

	var wantSum float64
	for _, v := range values {
		wantSum += v
		h.Observe(v)
	}

	gotCounts, gotInf, gotSum, gotCount := readHistogram(t, h)
	wantCounts := []uint64{2, 5, 8}
	if !reflect.DeepEqual(gotCounts, wantCounts) {
		t.Fatalf("bucket counts = %v, want %v", gotCounts, wantCounts)
	}
	if gotInf != uint64(len(values)) {
		t.Fatalf("+Inf count = %d, want %d", gotInf, len(values))
	}
	if gotSum != wantSum {
		t.Fatalf("sum = %v, want %v", gotSum, wantSum)
	}
	if gotCount != uint64(len(values)) {
		t.Fatalf("count = %d, want %d", gotCount, len(values))
	}
}

func readHistogram(t *testing.T, h *Histogram) ([]uint64, uint64, float64, uint64) {
	t.Helper()

	var b strings.Builder
	h.Write(&b)

	counts := make([]uint64, len(h.buckets))
	var inf uint64
	var sum float64
	var count uint64

	for _, line := range strings.Split(b.String(), "\n") {
		switch {
		case strings.Contains(line, `_bucket{le="+Inf"}`):
			inf = parseUintField(t, line)
		case strings.Contains(line, "_bucket"):
			for i, bucket := range h.buckets {
				if strings.Contains(line, fmt.Sprintf(`le="%v"`, bucket)) {
					counts[i] = parseUintField(t, line)
					break
				}
			}
		case strings.HasPrefix(line, h.name+"_sum "):
			sum = parseFloatField(t, line)
		case strings.HasPrefix(line, h.name+"_count "):
			count = parseUintField(t, line)
		}
	}

	return counts, inf, sum, count
}

func parseUintField(t *testing.T, line string) uint64 {
	t.Helper()

	fields := strings.Fields(line)
	if len(fields) != 2 {
		t.Fatalf("line %q has %d fields, want 2", line, len(fields))
	}
	v, err := strconv.ParseUint(fields[1], 10, 64)
	if err != nil {
		t.Fatalf("parse uint from %q: %v", line, err)
	}
	return v
}

func parseFloatField(t *testing.T, line string) float64 {
	t.Helper()

	fields := strings.Fields(line)
	if len(fields) != 2 {
		t.Fatalf("line %q has %d fields, want 2", line, len(fields))
	}
	v, err := strconv.ParseFloat(fields[1], 64)
	if err != nil {
		t.Fatalf("parse float from %q: %v", line, err)
	}
	return v
}
